pipeline.evaluate:
(() => {
  const filterJobId = ${{ args.job-id }} || '';
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('GET', 'https://www.zhipin.com/wapi/zpjob/job/chatted/jobList', true);
    xhr.withCredentials = true;
    xhr.timeout = 15000;
    xhr.setRequestHeader('Accept', 'application/json');
    xhr.onload = () => {
      try {
        const data = JSON.parse(xhr.responseText);
        if (data.code !== 0) reject(new Error(data.message));
        let jobs = data.zpData || [];
        if (filterJobId) jobs = jobs.filter(j => j.encryptJobId === filterJobId);
        resolve(jobs.map(j => ({ job_name: j.jobName || '', salary: j.salaryDesc || '', city: j.address || '', status: j.jobOnlineStatus === 1 ? '在线' : '已关闭', total_chats: '0', encrypt_job_id: j.encryptJobId || '' })));
      } catch(e) { reject(e); }
    };
    xhr.onerror = () => reject(new Error('Network Error'));
    xhr.send(null);
  });
})()
